Pseudobulk DE on the switch call

Switch+ vs switch- cells within 4s2M:
Each 4s2M sample contributes up to two pseudobulks (one switch+, one switch-)


Code
# Subset to the switched arm; each 4s2M sample contributes up to two pseudobulks (one switch+, one switch-).
sub_within &lt;- subset(mg, condition == "switched")
# AggregateExpression mangles underscores into hyphens and prepends 'g' to digit-leading strings, so we
# encode switch+/- as swP / swN to keep the suffix recoverable from the mangled column names.
sub_within$bulk_label &lt;- paste(sub_within$sample_id,
                               ifelse(sub_within$apoe_switch == "switch+", "swP", "swN"),
                               sep = "_")

bulk_within &lt;- AggregateExpression(sub_within,
                                   assays        = "Xenium",
                                   group.by      = "bulk_label",
                                   return.seurat = TRUE)

# Recover switch_call from the mangled suffix; "-swP" / "-swN" survive the underscore-to-hyphen rewrite.
bulk_within$switch_call &lt;- if_else(str_ends(colnames(bulk_within), "-swP"),
                                   "switch+", "switch-")
Idents(bulk_within) &lt;- "switch_call"

res_within &lt;- anayet(bulk_within,
                     ident1          = "switch+",
                     ident2          = "switch-",
                     test_method     = "DESeq2",
                     p_adj_threshold = 0.1,
                     min_pct         = 0.3,
                     plot_title      = "4s2M microglia DE",
                     print_plot      = FALSE)

# Side-by-side volcano + top-hit table, same idiom as the per-state loop in
# 20260518_microglia_pseudobulk_DE.qmd; falls back to top-5-by-raw-p when no gene clears FDR &lt; 0.1.
top_within &lt;- if (nrow(res_within$significant_results) &gt; 0) {
  res_within$significant_results |&gt;
    as_tibble(rownames = "gene") |&gt;
    select(gene, p_val, avg_log2FC, p_val_adj) |&gt;
    mutate(across(where(is.numeric), \(x) signif(x, 3))) |&gt;
    arrange(p_val_adj)
} else {
  res_within$all_results |&gt;
    as_tibble(rownames = "gene") |&gt;
    slice_min(p_val, n = 5, with_ties = FALSE) |&gt;
    select(gene, p_val, avg_log2FC, p_val_adj) |&gt;
    mutate(across(where(is.numeric), \(x) signif(x, 3)))
}
tbl_within &lt;- tableGrob(top_within, theme = ttheme_minimal(base_size = 11), rows = NULL)

res_within$volcano_plot + wrap_elements(tbl_within) + plot_layout(widths = c(3, 4))











E4 vs E2 sensitivity, restricted to switch+ in 4s2M
All cells in control mice (4s2) microglia vs. cells called as (switch +) in 4s2M mice microglia


Code
# 4s2 cells stay in full; 4s2M cells are restricted to switch+ so the "switched" arm is enriched for
# cells that actually carry E2 transcript.
sub_restr &lt;- subset(mg, condition == "control" |
                        (condition == "switched" & apoe_switch == "switch+"))

bulk_restr &lt;- AggregateExpression(sub_restr,
                                  assays        = "Xenium",
                                  group.by      = "sample_id",
                                  return.seurat = TRUE)

# Mirror the metadata-join idiom from the parent pseudobulk qmd: AggregateExpression rewrites
# "4s2_F1" -&gt; "g4s2-F1", so we reconstruct the lookup with the same transform.
sample_meta &lt;- sub_restr@meta.data |&gt;
  distinct(sample_id, condition) |&gt;
  mutate(bulk_id = paste0("g", gsub("_", "-", sample_id)))

bulk_restr$condition &lt;- sample_meta$condition[match(colnames(bulk_restr), sample_meta$bulk_id)]
stopifnot(!any(is.na(bulk_restr$condition)))
Idents(bulk_restr) &lt;- "condition"

res_restr &lt;- anayet(bulk_restr,
                    ident1          = "switched",
                    ident2          = "control",
                    test_method     = "DESeq2",
                    p_adj_threshold = 0.1,
                    min_pct         = 0.3,
                    plot_title      = "Restricted-to-switch+ DE",
                    print_plot      = FALSE)

top_restr &lt;- if (nrow(res_restr$significant_results) &gt; 0) {
  res_restr$significant_results |&gt;
    as_tibble(rownames = "gene") |&gt;
    select(gene, p_val, avg_log2FC, p_val_adj) |&gt;
    mutate(across(where(is.numeric), \(x) signif(x, 3))) |&gt;
    arrange(p_val_adj)
} else {
  res_restr$all_results |&gt;
    as_tibble(rownames = "gene") |&gt;
    slice_min(p_val, n = 5, with_ties = FALSE) |&gt;
    select(gene, p_val, avg_log2FC, p_val_adj) |&gt;
    mutate(across(where(is.numeric), \(x) signif(x, 3)))
}
tbl_restr &lt;- tableGrob(top_restr, theme = ttheme_minimal(base_size = 11), rows = NULL)

res_restr$volcano_plot + wrap_elements(tbl_restr) + plot_layout(widths = c(3, 4))











