# Persist both pseudobulk tables; rerun this chunk only after the upstream calibration has changed.
res_within$all_results |&gt;
  as_tibble(rownames = "gene") |&gt;
  write_csv("results/20260523-pseudobulk_DE_microglia_switchplus_vs_switchminus.csv")

res_restr$all_results |&gt;
  as_tibble(rownames = "gene") |&gt;
  write_csv("results/20260523-pseudobulk_DE_microglia_E4vsE2_switchplus_only.csv")
